"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[85387],{76123:e=>{e.exports=JSON.parse('{"tag":{"label":"nutrition","permalink":"/docs/tags/nutrition","allTagsPath":"/docs/tags","count":12,"items":[{"id":"Rats/getting-started/rat-care-guide","title":"A Comprehensive Guide to Rat Care","description":"Rats are intelligent, social, and engaging pets that bring a unique joy to any home. To ensure they live long, happy, and healthy lives, it\u2019s essential to understand and meet their specific needs. This guide provides a comprehensive overview of daily and weekly care routines for your pet rats.","permalink":"/docs/Rats/getting-started/rat-care-guide"},{"id":"Rats/breeds-and-genetics/rat-variety-guide","title":"A Guide to Fancy Rat Varieties","description":"Welcome to the colorful world of fancy rats! Through selective breeding, pet rats have been developed in a stunning array of colors, coat types, and markings. While these varieties are fascinating,...","permalink":"/docs/Rats/breeds-and-genetics/rat-variety-guide"},{"id":"Rats/getting-started/rat-nutrition-guide","title":"A Guide to Proper Rat Nutrition","description":"Proper nutrition is the cornerstone of your pet rat\'s health and longevity. As omnivores, rats have specific dietary needs that must be met to prevent obesity, nutritional deficiencies, and other...","permalink":"/docs/Rats/getting-started/rat-nutrition-guide"},{"id":"guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs","title":"Diabetes in Guinea Pigs","description":"Learn about diabetes mellitus in guinea pigs \u2014 causes, symptoms, diagnosis, management, and how diet and lifestyle changes can help your guinea pig live well.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/diabetes-in-guinea-pigs"},{"id":"Rats/getting-started/essential-rat-supplies","title":"Essential Rat Supplies","description":"Bringing pet rats home requires some preparation. Rats are intelligent, social animals with specific needs, and having the right supplies in place before they arrive will make the transition much smoother for both you and your new companions. This guide covers everything you need to set up a safe, comfortable, and enriching home for your rats.","permalink":"/docs/Rats/getting-started/essential-rat-supplies"},{"id":"guinea-pigs/getting-started/essential-supplies","title":"Essential Supplies for Guinea Pigs: A Helping All Little Things Guide","description":"Bringing home a guinea pig (or better yet\u2014a pair!) is an exciting and joyful experience. To set your new friends up for a happy, healthy life, it\u2019s important to have the right supplies ready from day...","permalink":"/docs/guinea-pigs/getting-started/essential-supplies"},{"id":"Rabbits/getting-started/essential-supplies-for-rabbits","title":"Essential Supplies for Your Rabbit Companion","description":"Bringing a rabbit into your home is a long-term commitment, and providing the right supplies is the first step to ensuring a happy, healthy life for your new friend. Rabbits have specific needs that...","permalink":"/docs/Rabbits/getting-started/essential-supplies-for-rabbits"},{"id":"Rabbits/health-and-wellness/home-health-care-for-your-rabbit","title":"Home Health Care for Your Rabbit","description":"Caring for a rabbit can be a deeply rewarding experience, bringing joy and companionship to your home. These intelligent and social creatures, capable of living up to 12\u201315 years, thrive with proper care and attention [1]. Understanding their unique needs \u2014 from diet to dental health and disease prevention \u2014 is crucial for ensuring a long and happy life for your furry friend. This guide walks you through essential aspects of home health care for your rabbit.","permalink":"/docs/Rabbits/health-and-wellness/home-health-care-for-your-rabbit"},{"id":"Rabbits/getting-started/nutrition","title":"Nutrition for Pet Rabbits","description":"A detailed guide to the correct diet for a pet rabbit, emphasizing the importance of hay and outlining the proper portions of greens, pellets, and treats.","permalink":"/docs/Rabbits/getting-started/nutrition"},{"id":"guinea-pigs/getting-started/nutrition-information","title":"Nutrition Information for Guinea Pigs","description":"A balanced and appropriate diet is the single most important factor in maintaining the health and well-being of your guinea pig. Unlike many other small pets, guinea pigs have specific and unique...","permalink":"/docs/guinea-pigs/getting-started/nutrition-information"},{"id":"Rats/getting-started/rat-treat-guide","title":"Rat Treat Guide","description":"This guide is meant to help you quickly check whether a food is generally safe as a treat for your rats. Research on rat nutrition is limited, so some guidance is based on related species or...","permalink":"/docs/Rats/getting-started/rat-treat-guide"},{"id":"guinea-pigs/illnesses-and-conditions/scurvy-in-guinea-pigs","title":"Scurvy (Vitamin C Deficiency) in Guinea Pigs","description":"Everything you need to know about scurvy in guinea pigs \u2014 causes, symptoms, treatment, and how to ensure your guinea pig gets enough Vitamin C.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/scurvy-in-guinea-pigs"}],"unlisted":false}}')}}]);